import{_ as a,c as t,a0 as r,o}from"./chunks/framework.CGHvQLJz.js";const m=JSON.parse('{"title":"vitepress","description":"","frontmatter":{},"headers":[],"relativePath":"blog/blog/vitepress.md","filePath":"blog/blog/vitepress.md"}'),s={name:"blog/blog/vitepress.md"};function i(l,e,p,n,d,h){return o(),t("div",null,e[0]||(e[0]=[r('<h1 id="vitepress" tabindex="-1">vitepress <a class="header-anchor" href="#vitepress" aria-label="Permalink to &quot;vitepress&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>vitepress 是一款静态网站构建工具，支持从 markdown 生成静态网站。</p><h2 id="为什么" tabindex="-1">为什么 <a class="header-anchor" href="#为什么" aria-label="Permalink to &quot;为什么&quot;">​</a></h2><p>在博客启动前，对比了 vitepress, astro, qwik。都支持文件结构即路由。</p><p>astro 的问题是，在 md 中嵌入复杂组件时，集成方式过于复杂。</p><p>qwik 的问题则在其无法使用 vue/react 等通用组件，而是自己又用了一套组件。当然也有其优势，能更好地控制 js 数量，实现秒加载。</p><p>vitepress 能方便地集成 vue 组件，成了首选项。</p><h2 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h2><h3 id="使用-emoji" tabindex="-1">使用 emoji <a class="header-anchor" href="#使用-emoji" aria-label="Permalink to &quot;使用 emoji&quot;">​</a></h3><p>语法：<code>:tada:</code>，对应：🎉</p><p>参考：<a href="https://github.com/markdown-it/markdown-it-emoji/blob/master/lib/data/full.mjs" target="_blank" rel="noreferrer">emoji 完整缩写列表</a></p>',12)]))}const b=a(s,[["render",i]]);export{m as __pageData,b as default};
